mapper.select:
SELECT id, user_id, instance_id, leave_type, 
    start_time, end_time, duration, reason, status, create_time
FROM att_leave_request
WHERE user_id = #{userId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limist}

mapper.update:
UPDATE att_leave_request
SET status = #{status}
WHERE id = #{id}

mapper.select:
SELECT  leave_type,
        total_days,
        used_days,
        (total_days - used_days) AS remaining_days
        FROM att_leave_quota
WHERE user_id = #{userId}
AND   year = #{year}
AND   leave_type = #{leaveType}

mapper.update:
UPDATE att_leave_quota
SET used_days = used_days + #{days}
WHERE user_id = #{userId}
AND   year = #{year}
AND   leave_type = #{leaveType}
AND   (total_days - used_days) >= #{days}
